messages.content:
下面给你一个「纯 HTML + CSS + JS」的贪吃蛇网页游戏，直接保存为 `snake.html` 双击打开就能玩（无需任何库）。支持：方向键/WSAD、暂停、重新开始、分数、速度随分数提升、碰墙/撞自己结束。

---

## 1）完整代码（保存为 snake.html）

```html
<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>贪吃蛇</title>
  <style>
    :root{
      --bg: #0f1220;
      --panel: #171a2b;
      --grid: #0b0e1a;
      --snake: #3ddc97;
      --snakeHead: #20c997;
      --food: #ff4d6d;
      --text: #e9edf5;
      --muted: #9aa3b2;
      --border: #2a2f45;
    }
    *{ box-sizing: border-box; }
    body{
      margin:0;
      font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "PingFang SC","Microsoft YaHei", sans-serif;
      background: radial-gradient(1200px 600px at 50% 0%, #1a1f3a 0%, var(--bg) 60%, #070912 100%);
      color: var(--text);
      min-height: 100vh;
      display:flex;
      align-items:center;
      justify-content:center;
      padding: 24px;
    }
    .wrap{
      width: min(820px, 96vw);
      display:grid;
      grid-template-columns: 1fr 260px;
      gap: 16px;
      align-items:start;
    }
    .card{
      background: color-mix(in srgb, var(--panel) 88%, transparent);
      border: 1px solid var(--border);
      border-radius: 14px;
      box-shadow: 0 18px 40px rgba(0,0,0,.35);
      overflow:hidden;
    }
    .canvasBox{
      padding: 14px;
    }
    canvas{
      width: 100%;
      height: auto;
      display:block;
      background:
        linear-gradient(var(--grid), var(--grid)) padding-box;
      border-radius: 12px;
      border: 1px solid rgba(255,255,255,.06);
    }
    .side{
      padding: 14px;
      display:flex;
      flex-direction:column;
      gap: 12px;
    }
    h1{
      font-size: 18px;
      margin: 2px 0 10px;
      letter-spacing: .5px;
    }
    .stats{
      display:grid;
      grid-template-columns: 1fr 1fr;
      gap: 10px;
    }
    .stat{
      background: rgba(255,255,255,.04);
      border: 1px solid rgba(255,255,255,.06);
      border-radius: 12px;
      padding: 10px;
    }
    .stat .k{ color: var(--muted); font-size: 12px; }
    .stat .v{ font-size: 18px; margin-top: 4px; }
    .btns{
      display:flex;
      gap: 10px;
      flex-wrap: wrap;
    }
    button{
      appearance:none;
      border: 1px solid rgba(255,255,255,.10);
      background: rgba(255,255,255,.06);
      color: var(--text);
      padding: 10px 12px;
      border-radius: 12px;
      cursor:pointer;
      transition: .15s;
      font-weight: 600;
    }
    button:hover{ background: rgba(255,255,255,.10); }
    button:active{ transform: translateY(1px); }
    .hint{
      color: var(--muted);
      font-size: 13px;
      line-height: 1.5;
      border-top: 1px dashed rgba(255,255,255,.10);
      padding-top: 10px;
    }
    .badge{
      display:inline-block;
      padding: 4px 8px;
      border-radius: 999px;
      background: rgba(255,255,255,.08);
      border: 1px solid rgba(255,255,255,.10);
      font-size: 12px;
      color: var(--muted);
    }
    @media (max-width: 820px){
      .wrap{ grid-template-columns: 1fr; }
    }
  </style>
</head>
<body>
  <div class="wrap">
    <div class="card canvasBox">
      <!-- 逻辑分辨率：600x600（方格更整齐）；CSS 会自适应缩放 -->
      <canvas id="game" width="600" height="600" aria-label="Snake Game"></canvas>
    </div>

    <div class="card side">
      <div>
        <h1>贪吃蛇 <span class="badge" id="stateBadge">准备</span></h1>
        <div class="stats">
          <div class="stat"><div class="k">分数</div><div class="v" id="score">0</div></div>
          <div class="stat"><div class="k">最高分</div><div class="v" id="best">0</div></div>
          <div class="stat"><div class="k">速度</div><div class="v" id="speed">1.0x</div></div>
          <div class="stat"><div class="k">长度</div><div class="v" id="len">3</div></div>
        </div>
      </div>

      <div class="btns">
        <button id="startBtn">开始</button>
        <button id="pauseBtn">暂停</button>
        <button id="restartBtn">重新开始</button>
      </div>

      <div class="hint">
        <div>操作：方向键 / W A S D</div>
        <div>空格：暂停/继续</div>
        <div>规则：吃到食物加分并变长；撞墙或撞到自己结束。</div>
      </div>
    </div>
  </div>

  <script>
    (() => {
      const canvas = document.getElementById('game');
      const ctx = canvas.getContext('2d');

      // 网格设置
      const GRID = 24;                 // 24x24
      const CELL = canvas.width / GRID; // 600/24=25
      const PADDING = 2;

      // UI
      const $score = document.getElementById('score');
      const $best = document.getElementById('best');
      const $speed = document.getElementById('speed');
      const $len = document.getElementById('len');
      const $badge = document.getElementById('stateBadge');

      const startBtn = document.getElementById('startBtn');
      const pauseBtn = document.getElementById('pauseBtn');
      const restartBtn = document.getElementById('restartBtn');

      // 存档最高分
      const BEST_KEY = 'snake_best_v1';
      let best = Number(localStorage.getItem(BEST_KEY) || 0);
      $best.textContent = best;

      // 游戏状态
      const State = { READY:'准备', RUNNING:'进行中', PAUSED:'暂停', OVER:'结束' };
      let state = 'READY';

      // 蛇 & 食物
      let snake, dir, nextDir, food, score;

      // 速度：基础间隔 + 随分数提升
      const BASE_MS = 140;
      let intervalMs = BASE_MS;
      let lastTick = 0;
      let rafId = 0;

      function setState(s){
        state = s;
        $badge.textContent = State[s] || s;
      }

      function randCell(){
        return {
          x: Math.floor(Math.random() * GRID),
          y: Math.floor(Math.random() * GRID)
        };
      }

      function sameCell(a,b){ return a.x === b.x && a.y === b.y; }

      function placeFood(){
        let p;
        do {
          p = randCell();
        } while (snake.some(seg => sameCell(seg, p)));
        food = p;
      }

      function resetGame(){
        // 初始蛇：向右
        snake = [
          {x: 6, y: 12},
          {x: 5, y: 12},
          {x: 4, y: 12},
        ];
        dir = {x: 1, y: 0};
        nextDir = {x: 1, y: 0};
        score = 0;

        intervalMs = BASE_MS;
        lastTick = 0;

        placeFood();
        updateUI();
        setState('READY');
        draw(); // 先画一帧
      }

      function updateUI(){
        $score.textContent = score;
        $len.textContent = snake.length;

        const speedMul = (BASE_MS / intervalMs).toFixed(1);
        $speed.textContent = `${speedMul}x`;

        if (score > best) {
          best = score;
          localStorage.setItem(BEST_KEY, String(best));
          $best.textContent = best;
        }
      }

      function isOpposite(a,b){
        return a.x + b.x === 0 && a.y + b.y === 0;
      }

      function setDir(d){
        // 防止 180 度掉头
        if (!isOpposite(d, dir)) nextDir = d;
      }

      function gameOver(){
        setState('OVER');
      }

      function step(){
        dir = nextDir;

        const head = snake[0];
        const newHead = { x: head.x + dir.x, y: head.y + dir.y };

        // 撞墙
        if (newHead.x < 0 || newHead.x >= GRID || newHead.y < 0 || newHead.y >= GRID){
          gameOver();
          return;
        }

        // 撞自己（注意：尾巴会移动，先判定时要考虑非增长情况）
        const willGrow = sameCell(newHead, food);
        const bodyToCheck = willGrow ? snake : snake.slice(0, -1);
        if (bodyToCheck.some(seg => sameCell(seg, newHead))){
          gameOver();
          return;
        }

        // 移动
        snake.unshift(newHead);

        if (willGrow){
          score += 10;
          placeFood();

          // 提速：每 50 分提升一点（最低间隔 60ms）
          const level = Math.floor(score / 50);
          intervalMs = Math.max(60, BASE_MS - level * 10);
        } else {
          snake.pop();
        }

        updateUI();
      }

      function drawCell(x, y, color, isHead=false){
        const px = x * CELL;
        const py = y * CELL;
        ctx.fillStyle = color;
        const r = isHead ? 8 : 7;
        const w = CELL - PADDING * 2;
        const h = CELL - PADDING * 2;

        // 圆角矩形
        roundRect(px + PADDING, py + PADDING, w, h, r);
        ctx.fill();
      }

      function roundRect(x, y, w, h, r){
        const rr = Math.min(r, w/2, h/2);
        ctx.beginPath();
        ctx.moveTo(x + rr, y);
        ctx.arcTo(x + w, y, x + w, y + h, rr);
        ctx.arcTo(x + w, y + h, x, y + h, rr);
        ctx.arcTo(x, y + h, x, y, rr);
        ctx.arcTo(x, y, x + w, y, rr);
        ctx.closePath();
      }

      function drawGrid(){
        // 背景
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // 轻微网格线
        ctx.save();
        ctx.globalAlpha = 0.14;
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 1;

        for (let i = 0; i <= GRID; i++){
          const p = i * CELL + 0.5;
          ctx.beginPath();
          ctx.moveTo(p, 0);
          ctx.lineTo(p, canvas.height);
          ctx.stroke();

          ctx.beginPath();
          ctx.moveTo(0, p);
          ctx.lineTo(canvas.width, p);
          ctx.stroke();
        }
        ctx.restore();
      }

      function draw(){
        drawGrid();

        // 食物
        drawCell(food.x, food.y, getCssVar('--food'));

        // 蛇
        snake.forEach((seg, i) => {
          drawCell(seg.x, seg.y, i === 0 ? getCssVar('--snakeHead') : getCssVar('--snake'), i === 0);
        });

        // 状态提示
        if (state === 'READY' || state === 'PAUSED' || state === 'OVER'){
          ctx.save();
          ctx.fillStyle = 'rgba(0,0,0,.45)';
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          ctx.fillStyle = '#fff';
          ctx.font = 'bold 38px system-ui, sans-serif';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';

          const text =
            state === 'READY' ? '按「开始」或回车开始' :
            state === 'PAUSED' ? '已暂停（空格继续）' :
            '游戏结束（回车重开）';

          ctx.fillText(text, canvas.width/2, canvas.height/2 - 12);

          ctx.font = '16px system-ui, sans-serif';
          ctx.fillStyle = 'rgba(255,255,255,.85)';
          ctx.fillText('方向键/WASD 控制方向', canvas.width/2, canvas.height/2 + 28);
          ctx.restore();
        }
      }

      function getCssVar(name){
        return getComputedStyle(document.documentElement).getPropertyValue(name).trim();
      }

      function loop(ts){
        rafId = requestAnimationFrame(loop);

        if (state !== 'RUNNING'){
          draw();
          return;
        }

        if (!lastTick) lastTick = ts;

        const delta = ts - lastTick;
        if (delta >= intervalMs){
          // 避免积累过多：对齐 tick
          lastTick = ts - (delta % intervalMs);
          step();
        }

        draw();
      }

      // 控制
      window.addEventListener('keydown', (e) => {
        const k = e.key.toLowerCase();

        if (k === 'arrowup' || k === 'w') setDir({x:0,y:-1});
        else if (k === 'arrowdown' || k === 's') setDir({x:0,y:1});
        else if (k === 'arrowleft' || k === 'a') setDir({x:-1,y:0});
        else if (k === 'arrowright' || k === 'd') setDir({x:1,y:0});
        else if (k === ' '){
          togglePause();
        } else if (k === 'enter'){
          if (state === 'READY') start();
          else restart();
        }
      });

      function start(){
        if (state === 'RUNNING') return;
        if (state === 'OVER') resetGame();
        setState('RUNNING');
      }

      function togglePause(){
        if (state === 'RUNNING') setState('PAUSED');
        else if (state === 'PAUSED') setState('RUNNING');
      }

      function restart(){
        resetGame();
        setState('RUNNING');
      }

      startBtn.addEventListener('click', start);
      pauseBtn.addEventListener('click', togglePause);
      restartBtn.addEventListener('click', restart);

      // 初始化
      resetGame();
      rafId = requestAnimationFrame(loop);
    })();
  </script>
</body>
</html>
```

---

## 2）你可以再告诉我想要的增强功能
比如：手机触控滑动、穿墙模式、关卡/障碍物、音效、皮肤、排行榜、难度选择等。我可以在你这版代码基础上直接改。

A/S/D 没反应最常见原因是：页面把焦点给了按钮（或某个可聚焦元素），同时浏览器/输入法对按键有拦截；另外你的代码里用的是 `e.key.toLowerCase()`，在少数输入法/键盘布局下可能拿到的不是 `"a" "s" "d"`。

你可以按下面顺序排查/修复（给你直接可用的改法）：

---

## 1）先确认事件是否触发（快速定位）
在 `keydown` 里临时加一行：

```js
console.log(e.key, e.code);
```

按 A/S/D 看控制台输出：
- 如果**完全没输出**：说明页面没有收到键盘事件（焦点/浏览器拦截/iframe 等问题）。
- 如果输出但不是 `a/s/d`（比如输出中文、或者别的字符）：说明 `e.key` 不稳定，建议改用 `e.code`。

---

## 2）推荐修复：用 `e.code` 判断（最稳）
把你原来的键盘监听替换为下面这段（同时保留方向键）：

```js
window.addEventListener('keydown', (e) => {
  // 防止方向键滚动页面
  if (['ArrowUp','ArrowDown','ArrowLeft','ArrowRight','Space'].includes(e.code)) {
    e.preventDefault();
  }

  switch (e.code) {
    case 'ArrowUp':
    case 'KeyW':
      setDir({x:0,y:-1}); break;

    case 'ArrowDown':
    case 'KeyS':
      setDir({x:0,y:1}); break;

    case 'ArrowLeft':
    case 'KeyA':
      setDir({x:-1,y:0}); break;

    case 'ArrowRight':
    case 'KeyD':
      setDir({x:1,y:0}); break;

    case 'Space':
      togglePause(); break;

    case 'Enter':
      if (state === 'READY') start();
      else restart();
      break;
  }
}, { passive: false });
```

说明：
- `e.code` 代表物理键位：`KeyA/KeyS/KeyD/KeyW`，不受输入法、大小写影响。
- `{ passive:false }` 配合 `preventDefault()`，避免浏览器默认行为干扰。

---

## 3）确保页面能拿到键盘焦点（偶发问题）
有些情况下点击按钮后，按键会被浏览器用于“按钮快捷键/页面搜索”等，建议给 canvas 可聚焦并在点击时聚焦：

在 HTML 的 canvas 上加 `tabindex`：
```html
<canvas id="game" width="600" height="600" tabindex="0"></canvas>
```

然后 JS 里加：
```js
canvas.addEventListener('click', () => canvas.focus());
canvas.focus();
```

---

如果你把你当前的 `keydown` 那段代码贴出来（或者你运行环境：直接双击打开、还是放在某个平台/iframe 里），我可以帮你精确定位是哪一种原因。

下面给你一份“分 2 屏双人对战”的贪吃蛇完整网页：左右各一块画布，同时开始/暂停/重开；各自吃各自的食物，撞墙或撞自己就淘汰，存活者获胜（同时死亡=平局）。  
玩家1：WASD；玩家2：方向键。

把下面代码保存为 `snake_2p.html` 直接打开即可。

---

```html
<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>双人贪吃蛇对战（分屏）</title>
  <style>
    :root{
      --bg: #0f1220;
      --panel: #171a2b;
      --grid: #0b0e1a;
      --text: #e9edf5;
      --muted: #9aa3b2;
      --border: #2a2f45;

      --p1: #3ddc97;
      --p1h:#20c997;
      --p1f:#ff4d6d;

      --p2: #4dabf7;
      --p2h:#339af0;
      --p2f:#ffd43b;
    }

    *{ box-sizing: border-box; }
    body{
      margin:0;
      font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "PingFang SC","Microsoft YaHei", sans-serif;
      background: radial-gradient(1200px 600px at 50% 0%, #1a1f3a 0%, var(--bg) 60%, #070912 100%);
      color: var(--text);
      min-height: 100vh;
      display:flex;
      align-items:center;
      justify-content:center;
      padding: 18px;
    }
    .wrap{
      width: min(1100px, 98vw);
      display:grid;
      grid-template-columns: 1fr;
      gap: 14px;
    }
    .topbar{
      display:flex;
      gap: 10px;
      flex-wrap: wrap;
      align-items:center;
      justify-content:space-between;
      background: color-mix(in srgb, var(--panel) 88%, transparent);
      border: 1px solid var(--border);
      border-radius: 14px;
      padding: 12px 14px;
      box-shadow: 0 18px 40px rgba(0,0,0,.25);
    }
    .title{
      display:flex; align-items:center; gap:10px;
      font-weight: 800;
      letter-spacing:.4px;
    }
    .badge{
      display:inline-block;
      padding: 5px 10px;
      border-radius: 999px;
      background: rgba(255,255,255,.08);
      border: 1px solid rgba(255,255,255,.10);
      font-size: 12px;
      color: var(--muted);
      white-space: nowrap;
    }
    .btns{ display:flex; gap:10px; flex-wrap: wrap; }
    button{
      appearance:none;
      border: 1px solid rgba(255,255,255,.10);
      background: rgba(255,255,255,.06);
      color: var(--text);
      padding: 10px 12px;
      border-radius: 12px;
      cursor:pointer;
      transition: .15s;
      font-weight: 700;
    }
    button:hover{ background: rgba(255,255,255,.10); }
    button:active{ transform: translateY(1px); }

    .boards{
      display:grid;
      grid-template-columns: 1fr 1fr;
      gap: 14px;
    }
    .card{
      background: color-mix(in srgb, var(--panel) 88%, transparent);
      border: 1px solid var(--border);
      border-radius: 14px;
      overflow:hidden;
      box-shadow: 0 18px 40px rgba(0,0,0,.25);
    }
    .head{
      display:flex;
      align-items:center;
      justify-content:space-between;
      gap: 10px;
      padding: 10px 12px;
      border-bottom: 1px solid rgba(255,255,255,.08);
    }
    .pname{ font-weight: 900; }
    .stats{ display:flex; gap:10px; flex-wrap: wrap; color: var(--muted); font-size: 13px; }
    .dot{
      width:10px;height:10px;border-radius:999px;display:inline-block; margin-right:8px;
      vertical-align: middle;
    }
    .canvasBox{ padding: 12px; }
    canvas{
      width: 100%;
      height: auto;
      display:block;
      background: linear-gradient(var(--grid), var(--grid)) padding-box;
      border-radius: 12px;
      border: 1px solid rgba(255,255,255,.06);
      outline: none;
    }

    .hint{
      color: var(--muted);
      font-size: 13px;
      line-height: 1.6;
      background: color-mix(in srgb, var(--panel) 88%, transparent);
      border: 1px solid var(--border);
      border-radius: 14px;
      padding: 12px 14px;
    }

    @media (max-width: 900px){
      .boards{ grid-template-columns: 1fr; }
    }
  </style>
</head>
<body>
  <div class="wrap">
    <div class="topbar">
      <div class="title">
        双人贪吃蛇对战（分屏）
        <span class="badge" id="stateBadge">准备</span>
        <span class="badge" id="resultBadge">—</span>
      </div>
      <div class="btns">
        <button id="startBtn">开始</button>
        <button id="pauseBtn">暂停</button>
        <button id="restartBtn">重新开始</button>
      </div>
    </div>

    <div class="boards">
      <div class="card">
        <div class="head">
          <div class="pname"><span class="dot" style="background:var(--p1)"></span>玩家1（WASD）</div>
          <div class="stats">
            <span>分数 <b id="p1Score">0</b></span>
            <span>长度 <b id="p1Len">3</b></span>
            <span>状态 <b id="p1Alive">存活</b></span>
          </div>
        </div>
        <div class="canvasBox">
          <canvas id="c1" width="520" height="520" tabindex="0"></canvas>
        </div>
      </div>

      <div class="card">
        <div class="head">
          <div class="pname"><span class="dot" style="background:var(--p2)"></span>玩家2（方向键）</div>
          <div class="stats">
            <span>分数 <b id="p2Score">0</b></span>
            <span>长度 <b id="p2Len">3</b></span>
            <span>状态 <b id="p2Alive">存活</b></span>
          </div>
        </div>
        <div class="canvasBox">
          <canvas id="c2" width="520" height="520" tabindex="0"></canvas>
        </div>
      </div>
    </div>

    <div class="hint">
      <div>玩家1：W/A/S/D 控制方向</div>
      <div>玩家2：方向键控制方向</div>
      <div>空格：暂停/继续；回车：重新开始</div>
      <div>规则：撞墙或撞到自己则淘汰；有一方淘汰则另一方获胜；同时淘汰=平局。</div>
    </div>
  </div>

  <script>
    (() => {
      const State = { READY:'准备', RUNNING:'进行中', PAUSED:'暂停', OVER:'结束' };
      let state = 'READY';

      const $stateBadge = document.getElementById('stateBadge');
      const $resultBadge = document.getElementById('resultBadge');

      const startBtn = document.getElementById('startBtn');
      const pauseBtn = document.getElementById('pauseBtn');
      const restartBtn = document.getElementById('restartBtn');

      function setState(s){
        state = s;
        $stateBadge.textContent = State[s] || s;
      }
      function setResult(text){
        $resultBadge.textContent = text || '—';
      }

      function cssVar(name){
        return getComputedStyle(document.documentElement).getPropertyValue(name).trim();
      }

      class PlayerBoard{
        constructor(opts){
          this.canvas = opts.canvas;
          this.ctx = this.canvas.getContext('2d');
          this.grid = opts.grid ?? 26; // 26x26
          this.cell = this.canvas.width / this.grid;
          this.pad = 2;

          this.colors = opts.colors; // {body, head, food}
          this.ui = opts.ui;         // {scoreEl, lenEl, aliveEl}
          this.spawn = opts.spawn;   // {snake, dir}

          this.reset();
        }

        reset(){
          this.alive = true;
          this.score = 0;
          // 深拷贝初始蛇
          this.snake = this.spawn.snake.map(s => ({...s}));
          this.dir = {...this.spawn.dir};
          this.nextDir = {...this.spawn.dir};
          this.placeFood();
          this.updateUI();
        }

        updateUI(){
          this.ui.scoreEl.textContent = this.score;
          this.ui.lenEl.textContent = this.snake.length;
          this.ui.aliveEl.textContent = this.alive ? '存活' : '淘汰';
          this.ui.aliveEl.style.color = this.alive ? 'inherit' : '#ff6b6b';
        }

        same(a,b){ return a.x===b.x && a.y===b.y; }
        isOpposite(a,b){ return a.x + b.x === 0 && a.y + b.y === 0; }

        setDir(d){
          if (!this.alive) return;
          if (!this.isOpposite(d, this.dir)) this.nextDir = d;
        }

        randCell(){
          return { x: Math.floor(Math.random()*this.grid), y: Math.floor(Math.random()*this.grid) };
        }

        placeFood(){
          let p;
          do { p = this.randCell(); }
          while (this.snake.some(seg => this.same(seg, p)));
          this.food = p;
        }

        step(){
          if (!this.alive) return;

          this.dir = this.nextDir;
          const head = this.snake[0];
          const nh = { x: head.x + this.dir.x, y: head.y + this.dir.y };

          // 撞墙
          if (nh.x < 0 || nh.x >= this.grid || nh.y < 0 || nh.y >= this.grid){
            this.alive = false;
            this.updateUI();
            return;
          }

          // 撞自己（不增长时尾巴会移走）
          const willGrow = this.same(nh, this.food);
          const bodyToCheck = willGrow ? this.snake : this.snake.slice(0, -1);
          if (bodyToCheck.some(seg => this.same(seg, nh))){
            this.alive = false;
            this.updateUI();
            return;
          }

          this.snake.unshift(nh);

          if (willGrow){
            this.score += 10;
            this.placeFood();
          } else {
            this.snake.pop();
          }

          this.updateUI();
        }

        roundRect(x, y, w, h, r){
          const ctx = this.ctx;
          const rr = Math.min(r, w/2, h/2);
          ctx.beginPath();
          ctx.moveTo(x + rr, y);
          ctx.arcTo(x + w, y, x + w, y + h, rr);
          ctx.arcTo(x + w, y + h, x, y + h, rr);
          ctx.arcTo(x, y + h, x, y, rr);
          ctx.arcTo(x, y, x + w, y, rr);
          ctx.closePath();
        }

        drawGrid(){
          const ctx = this.ctx;
          ctx.clearRect(0,0,this.canvas.width,this.canvas.height);

          ctx.save();
          ctx.globalAlpha = 0.14;
          ctx.strokeStyle = '#ffffff';
          ctx.lineWidth = 1;

          for (let i=0;i<=this.grid;i++){
            const p = i*this.cell + 0.5;
            ctx.beginPath(); ctx.moveTo(p,0); ctx.lineTo(p,this.canvas.height); ctx.stroke();
            ctx.beginPath(); ctx.moveTo(0,p); ctx.lineTo(this.canvas.width,p); ctx.stroke();
          }
          ctx.restore();
        }

        drawCell(x,y,color,isHead=false){
          const ctx = this.ctx;
          const px = x*this.cell;
          const py = y*this.cell;
          const w = this.cell - this.pad*2;
          const h = this.cell - this.pad*2;
          const r = isHead ? 9 : 8;
          ctx.fillStyle = color;
          this.roundRect(px+this.pad, py+this.pad, w, h, r);
          ctx.fill();
        }

        drawOverlay(text, sub){
          const ctx = this.ctx;
          ctx.save();
          ctx.fillStyle = 'rgba(0,0,0,.45)';
          ctx.fillRect(0,0,this.canvas.width,this.canvas.height);
          ctx.fillStyle = '#fff';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.font = 'bold 34px system-ui, sans-serif';
          ctx.fillText(text, this.canvas.width/2, this.canvas.height/2 - 14);
          ctx.font = '14px system-ui, sans-serif';
          ctx.fillStyle = 'rgba(255,255,255,.85)';
          if (sub) ctx.fillText(sub, this.canvas.width/2, this.canvas.height/2 + 22);
          ctx.restore();
        }

        draw(){
          this.drawGrid();
          this.drawCell(this.food.x, this.food.y, this.colors.food, false);
          this.snake.forEach((seg,i)=>{
            this.drawCell(seg.x, seg.y, i===0 ? this.colors.head : this.colors.body, i===0);
          });

          if (!this.alive){
            this.drawOverlay('已淘汰', '按回车可重新开始');
          }
        }
      }

      // 创建两块板
      const p1 = new PlayerBoard({
        canvas: document.getElementById('c1'),
        grid: 26,
        colors: { body: cssVar('--p1'), head: cssVar('--p1h'), food: cssVar('--p1f') },
        ui: {
          scoreEl: document.getElementById('p1Score'),
          lenEl: document.getElementById('p1Len'),
          aliveEl: document.getElementById('p1Alive')
        },
        spawn: {
          snake: [{x:6,y:13},{x:5,y:13},{x:4,y:13}],
          dir: {x:1,y:0}
        }
      });

      const p2 = new PlayerBoard({
        canvas: document.getElementById('c2'),
        grid: 26,
        colors: { body: cssVar('--p2'), head: cssVar('--p2h'), food: cssVar('--p2f') },
        ui: {
          scoreEl: document.getElementById('p2Score'),
          lenEl: document.getElementById('p2Len'),
          aliveEl: document.getElementById('p2Alive')
        },
        spawn: {
          snake: [{x:19,y:13},{x:20,y:13},{x:21,y:13}],
          dir: {x:-1,y:0}
        }
      });

      // 时间控制：同一节拍推进两边
      const BASE_MS = 120;
      let intervalMs = BASE_MS;
      let lastTick = 0;
      let rafId = 0;

      function computeSpeed(){
        // 简单：取两人最高分决定整体速度（也可以改为各自速度）
        const maxScore = Math.max(p1.score, p2.score);
        const level = Math.floor(maxScore / 50);
        intervalMs = Math.max(55, BASE_MS - level * 8);
      }

      function resetAll(){
        p1.reset();
        p2.reset();
        setResult('—');
        setState('READY');
        lastTick = 0;
        computeSpeed();
        drawAll();
      }

      function start(){
        if (state === 'OVER') resetAll();
        setState('RUNNING');
      }

      function togglePause(){
        if (state === 'RUNNING') setState('PAUSED');
        else if (state === 'PAUSED') setState('RUNNING');
      }

      function restart(){
        resetAll();
        setState('RUNNING');
      }

      function checkWinner(){
        // 只在进行中判断
        if (state !== 'RUNNING') return;

        if (!p1.alive && !p2.alive){
          setResult('平局（同时淘汰）');
          setState('OVER');
        } else if (!p1.alive && p2.alive){
          setResult('玩家2 获胜');
          setState('OVER');
        } else if (p1.alive && !p2.alive){
          setResult('玩家1 获胜');
          setState('OVER');
        }
      }

      function stepAll(){
        p1.step();
        p2.step();
        computeSpeed();
        checkWinner();
      }

      function drawAll(){
        p1.draw();
        p2.draw();

        if (state === 'READY' || state === 'PAUSED' || state === 'OVER'){
          // 在两块画布上都显示状态（更直观）
          const text =
            state === 'READY' ? '按「开始」或回车开始' :
            state === 'PAUSED' ? '已暂停（空格继续）' :
            '对局结束（回车重开）';
          const sub =
            '玩家1：WASD / 玩家2：方向键';

          p1.drawOverlay(text, sub);
          p2.drawOverlay(text, sub);
        }
      }

      function loop(ts){
        rafId = requestAnimationFrame(loop);

        if (state !== 'RUNNING'){
          drawAll();
          return;
        }
        if (!lastTick) lastTick = ts;

        const delta = ts - lastTick;
        if (delta >= intervalMs){
          lastTick = ts - (delta % intervalMs);
          stepAll();
        }
        drawAll();
      }

      // 键盘控制（用 e.code，最稳）
      window.addEventListener('keydown', (e) => {
        // 防止方向键/空格滚动页面
        if (['ArrowUp','ArrowDown','ArrowLeft','ArrowRight','Space'].includes(e.code)) {
          e.preventDefault();
        }

        switch (e.code){
          // P1: WASD
          case 'KeyW': p1.setDir({x:0,y:-1}); break;
          case 'KeyS': p1.setDir({x:0,y: 1}); break;
          case 'KeyA': p1.setDir({x:-1,y:0}); break;
          case 'KeyD': p1.setDir({x: 1,y:0}); break;

          // P2: Arrows
          case 'ArrowUp':    p2.setDir({x:0,y:-1}); break;
          case 'ArrowDown':  p2.setDir({x:0,y: 1}); break;
          case 'ArrowLeft':  p2.setDir({x:-1,y:0}); break;
          case 'ArrowRight': p2.setDir({x: 1,y:0}); break;

          // 全局
          case 'Space': togglePause(); break;
          case 'Enter': restart(); break;
        }
      }, { passive:false });

      startBtn.addEventListener('click', start);
      pauseBtn.addEventListener('click', togglePause);
      restartBtn.addEventListener('click', restart);

      // 允许点击画布后聚焦（可选）
      document.getElementById('c1').addEventListener('click', (e)=>e.currentTarget.focus());
      document.getElementById('c2').addEventListener('click', (e)=>e.currentTarget.focus());

      // init
      resetAll();
      rafId = requestAnimationFrame(loop);
    })();
  </script>
</body>
</html>
